sub _collect_iss_values {
    my ($self) = @_;

    $self->_normalize_exe_configuration();
    $self->_sync_derived_fields();

    my $app_name      = _trim($self->{iss_app_name}->GetValue);
    my $app_exe       = $self->_configured_exe_name();
    my $app_version   = _trim($self->{iss_app_version}->GetValue);
    my $app_publisher = _trim($self->{iss_app_publisher}->GetValue);

    my $appid_raw     = _trim($self->{iss_appid}->GetValue);
    my $dist_exe_path = $self->_built_exe_path();
    my $output_dir    = $self->_configured_release_path();
    my $output_base   = _trim($self->{iss_output_base}->GetValue);
    my $icon_path     = _trim($self->{iss_icon_path}->GetValue);

    $output_base =~ s/\.exe\z//i;
    $icon_path = $self->_resolve_project_file($icon_path) if $icon_path;

    my $scope_sel = $self->{iss_install_scope}->GetSelection;
    $scope_sel = 0 if !defined($scope_sel) || $scope_sel < 0;
    my $per_user = ($scope_sel == 0) ? 1 : 0;

    my $desktop_icon = $self->{iss_chk_desktop_icon}->GetValue ? 1 : 0;
    my $launch       = $self->{iss_chk_launch}->GetValue       ? 1 : 0;
    my $kill_running = $self->{iss_chk_kill_running}->GetValue ? 1 : 0;

    my $appid = _normalize_appid($appid_raw);

    return (
        $app_name,
        $app_exe,
        $app_version,
        $app_publisher,
        $appid,
        $dist_exe_path,
        $output_dir,
        $output_base,
        $icon_path,
        $per_user,
        $desktop_icon,
        $launch,
        $kill_running,
    );
}

sub generate_iss_preview {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::generate_iss_preview <event_handler>
    # end wxGlade

    my $cur = $self->{notebook_1}->GetSelection;
    if (!defined($cur) || $cur != TAB_INNO) {
        $self->_append_io("[iss] Not generating preview (ISS tab not active).\n");
        return;
    }

    my $script = _trim($self->{perl_script_path}->GetValue);
    if (!$script) {
        $self->_append_io("[iss] Not generating preview (no script selected).\n");
        return;
    }

    if ($self->{_iss_pending_seed}) {
        $self->_seed_iss_fields_from_script();
    }

    my (
        $app_name,
        $app_exe,
        $app_version,
        $app_publisher,
        $appid,
        $dist_exe_path,
        $output_dir,
        $output_base,
        $icon_path,
        $per_user,
        $desktop_icon,
        $launch,
        $kill_running,
    ) = $self->_collect_iss_values();

    my $appid_effective = $appid || ('{{' . _new_guid_upper() . '}}');

    my $priv_lines = $per_user
        ? "PrivilegesRequired=lowest\nPrivilegesRequiredOverridesAllowed=commandline"
        : "PrivilegesRequired=admin";

    my $setup_icon_line = $icon_path ? "SetupIconFile=$icon_path" : '';

    my $tasks_block = '';
    if ($desktop_icon) {
        $tasks_block = <<'TASKS';
[Tasks]

Name: "desktopicon"; Description: "Create a &desktop icon"; GroupDescription: "Additional icons:"
TASKS
    }

    my $run_block = '';
    if ($launch) {
        $run_block = <<RUN;
[Run]

Filename: "{app}\\{#MyAppExe}"; Description: "Launch {#MyAppName}"; Flags: nowait postinstall skipifsilent
RUN
    }

    my $code_block = '';
    if ($kill_running) {
        $code_block = <<CODE;
[Code]

function InitializeSetup(): Boolean;
var
  ResultCode: Integer;
begin
  // Close running version during upgrade
  Exec(
    ExpandConstant('{cmd}'),
    '/C taskkill /IM "{#MyAppExe}" /T /F >NUL 2>NUL',
    '',
    SW_HIDE,
    ewWaitUntilTerminated,
    ResultCode
  );

  Result := True;
end;
CODE
    }

    my $iss = <<"ISS";
; ------------------------------------------------------------
; Generated by wxPerl GUI Helper for Windows (Inno Setup tab)
; ------------------------------------------------------------

#define MyAppName "$app_name"
#define MyAppExe "$app_exe"
#define MyAppVersion "$app_version"
#define MyAppPublisher "$app_publisher"

[Setup]

AppId=$appid_effective

AppName={#MyAppName}
AppVersion={#MyAppVersion}
AppPublisher={#MyAppPublisher}

DefaultDirName={localappdata}\\Programs\\{#MyAppName}
DefaultGroupName={#MyAppName}

$priv_lines

UninstallDisplayIcon={app}\\{#MyAppExe}

Compression=lzma2
SolidCompression=yes
WizardStyle=modern

OutputDir=$output_dir
OutputBaseFilename=$output_base
ISS

    if ($setup_icon_line) {
        $iss .= $setup_icon_line . "\n";
    }

    $iss .= <<"ISS2";

[Files]

Source: "$dist_exe_path"; DestDir: "{app}"; Flags: ignoreversion

$tasks_block
[Icons]

; Start Menu shortcut
ISS2

    my $icon_param = '';
    if (defined($icon_path) && length($icon_path)) {
        $icon_param = qq{; IconFilename: "$icon_path"};
    }

    my $start_menu_line =
        qq{Name: "{userprograms}\\{#MyAppName}\\{#MyAppName}"; Filename: "{app}\\{#MyAppExe}"} . $icon_param;

    $iss .= $start_menu_line . "\n";

    $iss .= <<"ISS3";

; Uninstall shortcut
Name: "{userprograms}\\{#MyAppName}\\Uninstall {#MyAppName}"; Filename: "{uninstallexe}"
ISS3

    if ($desktop_icon) {
        my $icon_param = '';
        if (defined($icon_path) && length($icon_path)) {
            $icon_param = qq{; IconFilename: "$icon_path"};
        }

        my $line =
            qq{Name: "{userdesktop}\\{#MyAppName}"; Filename: "{app}\\{#MyAppExe}"; Tasks: desktopicon} . $icon_param;

        $iss .= "\n; Optional desktop shortcut\n$line\n";
    }

    $iss .= "\n";
    $iss .= $run_block  if $run_block;
    $iss .= "\n";
    $iss .= $code_block if $code_block;

    $self->_set_preview_text($iss);
    $self->{_q}->enqueue("[iss] Preview generated.\n");
}

sub save_iss_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::save_iss_file <event_handler>
    # end wxGlade

    my $cur = $self->{notebook_1}->GetSelection;
    if (!defined($cur) || $cur != TAB_INNO) {
        $self->_append_io("[iss] Not saving (ISS tab not active).\n");
        return;
    }

    my $script = _trim($self->{perl_script_path}->GetValue);
    if (!$script) {
        $self->_append_io("[iss] Not saving (no script selected).\n");
        return;
    }

    $self->generate_iss_preview(undef);
    my $text = $self->{iss_preview}->GetValue // '';
    if (!$text) {
        Wx::MessageBox("Nothing to save (preview is empty).", "Save .iss", wxOK|wxICON_INFORMATION, $self);
        return;
    }

    my $default_dir  = $self->{_iss_saved_path}
        ? File::Basename::dirname($self->{_iss_saved_path})
        : ($self->{_installer_dir} || '');
    my $default_name = $self->{_iss_saved_path}
        ? File::Basename::basename($self->{_iss_saved_path})
        : 'installer.iss';

    my $dlg = Wx::FileDialog->new(
        $self,
        "Save Inno Setup Script",
        $default_dir,
        $default_name,
        "Inno Setup Script (*.iss)|*.iss|All files (*.*)|*.*",
        Wx::wxFD_SAVE() | Wx::wxFD_OVERWRITE_PROMPT()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;

        if ($self->_write_text_file($path, $text)) {
            $self->{_iss_saved_path} = $path;
            Wx::MessageBox("Saved:\n$path", "Save .iss", wxOK|wxICON_INFORMATION, $self);
            $self->_append_io("[iss] Saved: $path\n");
        } else {
            Wx::MessageBox("Failed to save:\n$path\n\n$!", "Save .iss", wxOK|wxICON_ERROR, $self);
        }
    }

    $dlg->Destroy;
}

sub compile_iss_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::compile_iss_file <event_handler>
    # end wxGlade

    my $cur = $self->{notebook_1}->GetSelection;
    if (!defined($cur) || $cur != TAB_INNO) {
        $self->_append_io("[iss] Not compiling (ISS tab not active).\n");
        return;
    }

    my $script = _trim($self->{perl_script_path}->GetValue);
    if (!$script) {
        $self->_append_io("[iss] Not compiling (no script selected).\n");
        return;
    }

    $self->generate_iss_preview(undef);

    my $text = $self->_iss_preview_text();
    if (!$text) {
        Wx::MessageBox(
            "Nothing to compile. The .iss preview is empty.",
            "Compile .iss",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    my $iscc = _expand_env_vars_windows($self->{text_iss_exe}->GetValue);
    if (!$iscc) {
        Wx::MessageBox(
            "Please set the path to ISCC.exe first.",
            "Compile .iss",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    if (!-f $iscc) {
        Wx::MessageBox(
            "ISCC.exe was not found:\n$iscc",
            "Compile .iss",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    my $iss_path = $self->_ensure_iss_path_for_save();
    if (!$iss_path) {
        $self->_append_io("[iss] Compile cancelled (no .iss save path selected).\n");
        return;
    }

    if (!$self->_save_iss_to_path($iss_path)) {
        Wx::MessageBox(
            "Failed to save the .iss file before compiling.\n\n$!",
            "Compile .iss",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    my $installer_path = $self->_compute_expected_installer_path($iss_path);

    $self->{_iss_has_compiled}        = 0;
    $self->{_iss_last_compile_exit}   = undef;
    $self->{_iss_last_installer_path} = '';

    $self->_append_io("\n=== Inno Setup compile ===\n");
    $self->_append_io("[iss] ISCC.exe=$iscc\n");
    $self->_append_io("[iss] Script=$iss_path\n");
    $self->_append_io("[iss] Expected installer=" . ($installer_path || '(unknown)') . "\n\n");

    my $q = $self->{_q};

    threads->create(sub {
        my ($iscc_path, $script_path, $expected_installer, $qref) = @_;

        my $cmd = qq{"$iscc_path" "$script_path" 2>&1};
        my $exit = 0;

        $qref->enqueue({
            type => 'ISS_COMPILE_BEGIN',
            text => "[iss] compiling with:\n$cmd\n\n",
        });

        if (open(my $fh, "$cmd |")) {
            while (my $line = <$fh>) {
                $qref->enqueue({
                    type => 'ISS_COMPILE_LINE',
                    text => $line,
                });
            }
            close($fh);
            $exit = $? >> 8;
        } else {
            $qref->enqueue({
                type => 'ISS_COMPILE_LINE',
                text => "[worker][error] failed to run ISCC.exe: $!\n",
            });
            $exit = 127;
        }

        $qref->enqueue({
            type           => 'ISS_COMPILE_DONE',
            exit_code      => $exit,
            installer_path => $expected_installer,
        });
        return;
    }, $iscc, $iss_path, $installer_path, $q)->detach();
}

sub load_iss_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::load_iss_file <event_handler>
    # end wxGlade

    my $default_dir  = $self->{_iss_saved_path}
        ? File::Basename::dirname($self->{_iss_saved_path})
        : ($self->{_installer_dir} || $self->{_proj_root} || '');
    my $default_name = $self->{_iss_saved_path}
        ? File::Basename::basename($self->{_iss_saved_path})
        : 'installer.iss';

    my $dlg = Wx::FileDialog->new(
        $self,
        "Load Inno Setup Script",
        $default_dir,
        $default_name,
        "Inno Setup Script (*.iss)|*.iss|All files (*.*)|*.*",
        Wx::wxFD_OPEN() | Wx::wxFD_FILE_MUST_EXIST()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;
        my $text = $self->_read_text_file($path);

        if ($text ne '') {
            $self->_set_preview_text($text);
            $self->_load_iss_into_form($text, $path);
            $self->{_iss_has_compiled}       = 0;
            $self->{_iss_last_compile_exit}  = undef;
            $self->{_iss_last_installer_path}= '';
            $self->_append_io("[iss] Loaded: $path\n");

            Wx::MessageBox(
                "Loaded:\n$path",
                "Load .iss",
                wxOK | wxICON_INFORMATION,
                $self
            );
        } else {
            Wx::MessageBox(
                "Failed to load:\n$path\n\n$!",
                "Load .iss",
                wxOK | wxICON_ERROR,
                $self
            );
        }
    }

    $dlg->Destroy;
}

sub run_app_installer {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::run_app_installer <event_handler>
    # end wxGlade

    $self->_sync_derived_fields();

    my $installer = $self->_installer_exe_path();
    $installer ||= _trim($self->{_iss_last_installer_path});

    if (!$installer) {
        Wx::MessageBox(
            "Set Installer Output Directory (RELEASE) and Installer Base Filename first.",
            "Test Installer",
            wxOK | wxICON_INFORMATION,
            $self
        );
        return;
    }

    $installer = _expand_env_vars_windows($installer);

    if (!-f $installer) {
        Wx::MessageBox(
            "Installer was not found:\n$installer",
            "Test Installer",
            wxOK | wxICON_ERROR,
            $self
        );
        return;
    }

    my $run_dir = File::Basename::dirname($installer);

    $self->_append_io("\n=== Testing Installer ===\n");
    $self->_append_io("[iss] Installer=$installer\n\n");

    my $q = $self->{_q};

    threads->create(sub {
        my ($path, $dir, $qref) = @_;

        my $orig = eval { Cwd::getcwd() } || '';
        my $exit = 0;

        if (!chdir $dir) {
            $qref->enqueue("[worker][error] failed to chdir to '$dir': $!\n");
            $qref->enqueue("[installer done] exit_code=1\n");
            return;
        }

        $qref->enqueue("[worker] current directory: $dir\n");
        $qref->enqueue("[worker] starting installer: $path\n");

        my $cmd = qq{"$path" 2>&1};

        if (open(my $fh, "$cmd |")) {
            while (my $line = <$fh>) {
                $qref->enqueue($line);
            }
            close($fh);
            $exit = $? >> 8;
        }
        else {
            $qref->enqueue("[worker][error] failed to run installer '$path': $!\n");
            $exit = 127;
        }

        chdir $orig if $orig;
        $qref->enqueue("[installer done] exit_code=$exit\n");
        return;
    }, $installer, $run_dir, $q)->detach();
}

sub select_iss_exe {
