sub load_project_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::load_project_file <event_handler>
    # end wxGlade

    my $dlg = Wx::FileDialog->new(
        $self,
        "Open Project",
        $self->_project_default_dir,
        $self->_project_default_name,
        "wxPerl Helper Project (*.wxp)|*.wxp|JSON files (*.json)|*.json|All files (*.*)|*.*",
        Wx::wxFD_OPEN() | Wx::wxFD_FILE_MUST_EXIST()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;
        my $text = $self->_read_text_file($path);

        if (!$text) {
            Wx::MessageBox(
                "Failed to load:
$path

$!",
                "Open Project",
                wxOK | wxICON_ERROR,
                $self
            );
            $dlg->Destroy;
            return;
        }

        my $data;
        my $ok = eval {
            $data = JSON::PP->new->decode($text);
            1;
        };

        if (!$ok || ref($data) ne 'HASH') {
            my $err = $@ || 'Project file is not valid JSON.';
            Wx::MessageBox(
                "Failed to parse project file:
$path

$err",
                "Open Project",
                wxOK | wxICON_ERROR,
                $self
            );
            $dlg->Destroy;
            return;
        }

        $self->_apply_project_state($data, $path);
        $self->_append_io("[project] Loaded: $path
");

        Wx::MessageBox(
            "Loaded:
$path",
            "Open Project",
            wxOK | wxICON_INFORMATION,
            $self
        );
    }

    $dlg->Destroy;
}


sub save_project_file {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::save_project_file <event_handler>
    # end wxGlade

    my $path = _trim($self->{_project_saved_path});
    if (!$path) {
        return $self->save_project_file_as($event);
    }

    if ($self->_save_project_to_path($path)) {
        $self->_append_io("[project] Saved: $path
");
        Wx::MessageBox("Saved:
$path", "Save Project", wxOK | wxICON_INFORMATION, $self);
        return;
    }

    Wx::MessageBox("Failed to save:
$path

$!", "Save Project", wxOK | wxICON_ERROR, $self);
}


sub save_project_file_as {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::save_project_file_as <event_handler>
    # end wxGlade

    my $dlg = Wx::FileDialog->new(
        $self,
        "Save Project As",
        $self->_project_default_dir,
        $self->_project_default_name,
        "wxPerl Helper Project (*.wxp)|*.wxp|JSON files (*.json)|*.json|All files (*.*)|*.*",
        Wx::wxFD_SAVE() | Wx::wxFD_OVERWRITE_PROMPT()
    );

    if ($dlg->ShowModal == Wx::wxID_OK()) {
        my $path = $dlg->GetPath;
        if ($path !~ /\.(?:wxp|json)$/i) {
            $path .= '.wxp';
        }

        if ($self->_save_project_to_path($path)) {
            $self->_append_io("[project] Saved: $path
");
            Wx::MessageBox("Saved:
$path", "Save Project As", wxOK | wxICON_INFORMATION, $self);
        } else {
            Wx::MessageBox("Failed to save:
$path

$!", "Save Project As", wxOK | wxICON_ERROR, $self);
        }
    }

    $dlg->Destroy;
}

sub start_new_project {
    my ($self, $event) = @_;
    # wxGlade: MyFrame::start_new_project <event_handler>
    # end wxGlade

    $self->{perl_script_path}->ChangeValue('') if $self->{perl_script_path};
    $self->{txt_cmd_io}->SetValue('')          if $self->{txt_cmd_io};
    $self->_set_preview_text('');

    $self->{_iss_seeded_from_script}   = 0;
    $self->{_iss_pending_seed}         = 0;
    $self->{_script_abs}               = '';
    $self->{_proj_root}                = '';
    $self->{_installer_dir}            = '';
    $self->{_dist_dir}                 = '';
    $self->{_release_dir}              = '';
    $self->{_generated_makefile}       = '';
    $self->{_makefile_saved_path}      = '';
    $self->{_last_make_exit_code}      = undef;
    $self->{_iss_saved_path}           = '';
    $self->{_iss_last_installer_path}  = '';
    $self->{_iss_has_compiled}         = 0;
    $self->{_iss_last_compile_exit}    = undef;
    $self->{_project_saved_path}       = '';

    $self->_reset_run_exe_state();
    $self->_apply_safe_default_paths();

    $self->{iss_app_name}->SetValue('My Program')
        if $self->{iss_app_name};
    $self->{iss_app_version}->SetValue('1.0.0')
        if $self->{iss_app_version};
    $self->{iss_app_publisher}->SetValue('Perl Community Org')
        if $self->{iss_app_publisher};
    $self->{iss_appid}->SetValue('not yet generated ...')
        if $self->{iss_appid};
    $self->{iss_output_base}->SetValue('myprog-setup')
        if $self->{iss_output_base};
    $self->{iss_icon_path}->SetValue('')
        if $self->{iss_icon_path};
    $self->{iss_install_scope}->SetSelection(0)
        if $self->{iss_install_scope};
    $self->{iss_chk_desktop_icon}->SetValue(1)
        if $self->{iss_chk_desktop_icon};
    $self->{iss_chk_launch}->SetValue(1)
        if $self->{iss_chk_launch};
    $self->{iss_chk_kill_running}->SetValue(1)
        if $self->{iss_chk_kill_running};
    $self->{text_iss_exe}->SetValue(
        '%LOCALAPPDATA%\\Programs\\Inno Setup 6\\ISCC.exe'
    ) if $self->{text_iss_exe};

    $self->_sync_derived_fields();
    $self->{notebook_1}->SetSelection(TAB_GENERAL)
        if $self->{notebook_1};
    $self->_refresh_run_makefile_button_state();
    $self->_append_io("[project] Started new project.\n");
}

